-- ลบ contracts Boonphone เก่า (4212 rows — ข้อมูลไม่ครบ)
DELETE FROM contracts WHERE section = 'Boonphone';

-- ลบ installments Boonphone เก่า
DELETE FROM installments WHERE section = 'Boonphone';

-- Rename boonphone → Boonphone ใน contracts
UPDATE contracts SET section = 'Boonphone' WHERE section = 'boonphone';

-- Rename boonphone → Boonphone ใน installments
UPDATE installments SET section = 'Boonphone' WHERE section = 'boonphone';

-- Normalize payment_transactions: ff365 → Fastfone365, boonphone → Boonphone
UPDATE payment_transactions SET section = 'Fastfone365' WHERE section = 'ff365';
UPDATE payment_transactions SET section = 'Boonphone' WHERE section = 'boonphone';

-- ตรวจสอบผลลัพธ์
SELECT 'contracts' as tbl, section, COUNT(*) as cnt FROM contracts GROUP BY section
UNION ALL
SELECT 'installments', section, COUNT(*) FROM installments GROUP BY section
UNION ALL
SELECT 'payment_transactions', section, COUNT(*) FROM payment_transactions GROUP BY section
ORDER BY tbl, section;

